class OpenAIModelComponent(LCModelComponent):
    display_name = 'OpenAI'
    description = 'Generates text using OpenAI LLMs.'
    icon = 'OpenAI'
    name = 'OpenAIModel'
    inputs = [*LCModelComponent.get_base_inputs(), IntInput(name='max_tokens', display_name='Max Tokens', advanced=True, info='The maximum number of tokens to generate. Set to 0 for unlimited tokens.', range_spec=RangeSpec(min=0, max=128000)), DictInput(name='model_kwargs', display_name='Model Kwargs', advanced=True, info='Additional keyword arguments to pass to the model.'), BoolInput(name='json_mode', display_name='JSON Mode', advanced=True, info='If True, it will output JSON regardless of passing a schema.'), DropdownInput(name='model_name', display_name='Model Name', advanced=False, options=OPENAI_CHAT_MODEL_NAMES + OPENAI_REASONING_MODEL_NAMES, value=OPENAI_CHAT_MODEL_NAMES[0], combobox=True, real_time_refresh=True), StrInput(name='openai_api_base', display_name='OpenAI API Base', advanced=True, info='The base URL of the OpenAI API. Defaults to https://api.openai.com/v1. You can change this to use other APIs like JinaChat, LocalAI and Prem.'), SecretStrInput(name='api_key', display_name='OpenAI API Key', info='The OpenAI API Key to use for the OpenAI model.', advanced=False, value='OPENAI_API_KEY', required=True), SliderInput(name='temperature', display_name='Temperature', value=0.1, range_spec=RangeSpec(min=0, max=1, step=0.01), show=True), IntInput(name='seed', display_name='Seed', info='The seed controls the reproducibility of the job.', advanced=True, value=1), IntInput(name='max_retries', display_name='Max Retries', info='The maximum number of retries to make when generating.', advanced=True, value=5), IntInput(name='timeout', display_name='Timeout', info='The timeout for requests to OpenAI completion API.', advanced=True, value=700)]

    def build_model(self) -> LanguageModel:
        logger.debug(f'Executing request with model: {self.model_name}')
        logger.debug(f"API key type: {type(self.api_key)}, value: {('***' if self.api_key else None)}")
        api_key_value = secret_value_to_str(self.api_key) if self.api_key else None
        logger.debug(f"Final api_key_value type: {type(api_key_value)}, value: {('***' if api_key_value else None)}")
        model_kwargs = self.model_kwargs or {}
        if 'api_key' in model_kwargs:
            logger.warning('api_key found in model_kwargs, removing to prevent conflicts')
            model_kwargs = dict(model_kwargs)
            del model_kwargs['api_key']
        parameters = {'api_key': api_key_value, 'model_name': self.model_name, 'max_tokens': self.max_tokens or None, 'model_kwargs': model_kwargs, 'base_url': self.openai_api_base or 'https://api.openai.com/v1', 'max_retries': self.max_retries, 'timeout': self.timeout}
        unsupported_params_for_reasoning_models = ['temperature', 'seed']
        if self.model_name not in OPENAI_REASONING_MODEL_NAMES:
            parameters['temperature'] = self.temperature if self.temperature is not None else 0.1
            parameters['seed'] = self.seed
        else:
            params_str = ', '.join(unsupported_params_for_reasoning_models)
            logger.debug(f'{self.model_name} is a reasoning model, {params_str} are not configurable. Ignoring.')
        parameters['stream_usage'] = True
        output = ChatOpenAI(**parameters)
        if self.json_mode:
            output = output.bind(response_format={'type': 'json_object'})
        return output

    def _get_exception_message(self, e: Exception):
        try:
            from openai import BadRequestError, NotFoundError
        except ImportError:
            return None
        if isinstance(e, NotFoundError):
            body = getattr(e, 'body', None) or {}
            if isinstance(body, dict) and body.get('code') == 'model_not_found':
                return f"Model '{self.model_name}' is not available for this OpenAI account. Your API tier may not have access yet — check https://platform.openai.com/settings/organization/limits or select a different model."
        if isinstance(e, BadRequestError):
            message = e.body.get('message')
            if message:
                return message
        return None

    def update_build_config(self, build_config: dict, field_value: Any, field_name: str | None=None) -> dict:
        if field_name in {'base_url', 'model_name', 'api_key'} and field_value in OPENAI_REASONING_MODEL_NAMES:
            build_config['temperature']['show'] = False
            build_config['seed']['show'] = False
            if field_value.startswith('o1') and 'system_message' in build_config:
                build_config['system_message']['show'] = False
        if field_name in {'base_url', 'model_name', 'api_key'} and field_value in OPENAI_CHAT_MODEL_NAMES:
            build_config['temperature']['show'] = True
            build_config['seed']['show'] = True
            if 'system_message' in build_config:
                build_config['system_message']['show'] = True
        return build_config

import contextlib
from datetime import datetime, timezone
from langchain_classic.agents import create_tool_calling_agent
from langchain_core.prompts import ChatPromptTemplate
from lfx.base.agents.agent import LCToolsAgentComponent
from lfx.base.agents.default_system_prompt import DEFAULT_SYSTEM_PROMPT_TEMPLATE, has_env_placeholders, substitute_env_placeholders
from lfx.base.models.model_utils import get_model_name
from lfx.base.models.unified_models import get_language_model_options, get_llm, handle_model_input_update
from lfx.base.models.watsonx_constants import IBM_WATSONX_URLS
from lfx.components.langchain_utilities.ibm_granite_handler import create_granite_agent, get_enhanced_system_prompt, is_granite_model
