import httpx

class SCIMProvisioningTools(Component):
    display_name = 'SCIM Provisioning Tools'
    description = 'SCIM 2.0 identity-provider tools: create a user and list/search users.'
    icon = 'user-plus'
    name = 'SCIMProvisioningTools'
    inputs = [MessageTextInput(name='scim_users_url', display_name='SCIM Users URL', value='https://idp.{{DOMAIN}}/scim/v2/Users', info='Base SCIM /Users endpoint of the Identity Provider.'), SecretStrInput(name='scim_token', display_name='SCIM Bearer Token', value='__IDP_SCIM_TOKEN__', info='Bearer token for the SCIM API.')]
    outputs = [Output(display_name='Tools', name='tools', method='build_tools')]

    def build_tools(self) -> list[Tool]:
        url = (self.scim_users_url or '').strip()
        token = self.scim_token or ''

        def _post_headers():
            return {'Authorization': f'Bearer {token}', 'Content-Type': 'application/scim+json', 'Accept': 'application/scim+json'}

        def _get_headers():
            return {'Authorization': f'Bearer {token}', 'Accept': 'application/scim+json'}

        def scim_create_user(email: str, given_name: str, family_name: str) -> str:
            body = {'schemas': ['urn:ietf:params:scim:schemas:core:2.0:User'], 'userName': email, 'name': {'givenName': given_name, 'familyName': family_name}, 'displayName': f'{given_name} {family_name}', 'emails': [{'value': email, 'primary': True}], 'active': True}
            try:
                r = httpx.post(url, headers=_post_headers(), json=body, timeout=30.0)
                return f'HTTP {r.status_code}\n{r.text[:1500]}'
            except Exception as e:
                return f'Request failed: {e}'

        def scim_list_users(scim_filter: str='', count: int=50) -> str:
            params = {}
            if scim_filter:
                params['filter'] = scim_filter
            if count:
                params['count'] = count
            try:
                r = httpx.get(url, headers=_get_headers(), params=params, timeout=30.0)
                return f'HTTP {r.status_code}\n{r.text[:1500]}'
            except Exception as e:
                return f'Request failed: {e}'

        class CreateArgs(BaseModel):
            email: str = Field(..., description="The new user's email address; used as the SCIM userName.")
            given_name: str = Field(..., description="The user's first name (givenName).")
            family_name: str = Field(..., description="The user's last name (familyName).")

        class ListArgs(BaseModel):
            scim_filter: str = Field('', description='Optional SCIM filter, e.g. userName eq "jane.doe@example.com".')
            count: int = Field(50, description='Maximum number of users to return.')
        tools = [StructuredTool.from_function(func=scim_create_user, name='SCIM_Create_User', description="Provision (create) a NEW user in the Identity Provider via SCIM 2.0. Requires the person's email, first name and last name.", args_schema=CreateArgs), StructuredTool.from_function(func=scim_list_users, name='SCIM_List_Users', description='List or search existing users in the Identity Provider via SCIM 2.0. Optionally pass a SCIM filter and a count.', args_schema=ListArgs)]
        self.status = f'SCIM tools ready against {url}'
        return tools
